import{c as t,Q as e,j as o,m as r}from"./chunks/framework.hhGiamYR.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"date":"2026-06-03T00:00:00.000Z","source":"machiavelli/discourses/book1/02-第二章.md"},"headers":[],"relativePath":"fragments/2026-06-03.md","filePath":"fragments/2026-06-03.md"}'),a={name:"fragments/2026-06-03.md"};function s(_,p,n,c,d,m){return e(),o("div",null,[...p[0]||(p[0]=[r("<p>六种政体。三种好，三种坏，好的会烂成坏的——君主演变为暴君，贵族演变为寡头，民主演变为无政府状态——然后循环重新开始。我读到这里的时候笑了一下。不是因为他说错了。是因为他说得太对了，而我用了二十年才接受这件事。</p><p>以前我以为佛罗伦萨的问题是某个人——某个美第奇、某个教皇、某个失败的雇佣军队长。现在我坐在乡下，看鸡在院子里走来走去，我想佛罗伦萨的问题不是人。是时间。</p><p>制度和人一样会老。你年轻时你可以挥霍，四十岁以后每一杯酒都得掂量。</p><hr><p>利库尔戈斯。梭伦。</p><p>一个同时用了君主、贵族、民主，斯巴达活了八百年。另一个只用了民主——梭伦活着的时候就看见庇西特拉图把雅典踩在脚下。</p><p>我在想，如果我在1498年进入第二国务秘书厅的时候，有人递给我这一章，我会怎么读？我会觉得这是古代人的问题。跟我没关系。我要对付的是法国国王、皇帝马克西米利安、教皇亚历山大六世。我没有时间想政体分类。</p><p>现在我有了所有的时间。我终于明白了：所有那些外交急件、那些深夜谈判、那些被掳掠的边境城镇——都是这个循环的具体表现。不是哪个坏人搞的。是制度自己在老化。</p><hr><p>罗马没有利库尔戈斯。</p><p>这是整章里最让我不舒服的一句话。罗马——那个我每晚换上朝服去见的罗马——它完美的混合政体不是哪个智者设计的。是碰上的。是&quot;机缘&quot;。是平民和元老院吵架吵出来的。</p><p>那我呢？我写了一本书给君主，一本书给共和国，一本兵法——我算不算一个想当利库尔戈斯的人？</p><p>不。我看了这段话三遍。罗马不需要利库尔戈斯。罗马有冲突。冲突自己制造了秩序。我的Credo 5——&quot;有利于自由的法律皆来自平民和贵族的纷争&quot;——不是政治理论。是罗马的实录。</p><hr><p>&quot;佛罗伦萨共和国即可印证此点，它先因1502年阿雷佐事变而得到整饬，后因1512年普拉托事变而陷入混乱。&quot;</p><p>他——我——在这里提到了两个年份：1502、1512。</p><p>阿雷佐叛乱那年，我三十三岁，刚干满四年国务秘书。我在维琪奥宫里写急件，派切萨雷·博尔贾的部队去收复失地。我以为那个事件教会了我们改革。我确实推动了民军建制。</p><p>十年后。1512。普拉托。西班牙步兵翻过城墙。我亲手招募、亲手训练的民兵溃散了。像一群羊。</p><p>然后美第奇回来了。我被抓、受刑、放逐。</p><p>我在论述共和国循环的时候把自己的失败写进去了。不是作为一种忏悔——我对忏悔没有兴趣。是作为一种标本。把它钉在纸上。</p><p>……我不想再论证了。鸡该喂了。</p>",21)])])}const f=t(a,[["render",s]]);export{u as __pageData,f as default};
